const items = $input.all();
if (items.length === 0) { return []; }
const gbpTotal = items.filter(i => i.json.currency === 'GBP').reduce((s, i) => s + Number(i.json.amount_entitled), 0);
const eurTotal = items.filter(i => i.json.currency === 'EUR').reduce((s, i) => s + Number(i.json.amount_entitled), 0);
const maxItem = items.reduce((m, i) => Number(i.json.amount_entitled) > Number(m.json.amount_entitled) ? i : m);
return [{ json: { count: items.length, gbpTotal, eurTotal, maxAmount: maxItem.json.amount_entitled, maxName: maxItem.json.account_name, weekRef: items[0].json.week_ref, claims: items.map(i => i.json) } }];
